package com.jucheonsu.port.domain.project.service;
import com.jucheonsu.port.domain.portfolio.entity.Portfolio;import com.jucheonsu.port.domain.portfolio.repository.PortfolioRepository;import com.jucheonsu.port.domain.project.converter.ProjectConverter;import com.jucheonsu.port.domain.project.dto.request.*;import com.jucheonsu.port.domain.project.dto.response.ProjectResponse;import com.jucheonsu.port.domain.project.entity.Project;import com.jucheonsu.port.domain.project.repository.ProjectRepository;import com.jucheonsu.port.global.exception.*;import lombok.RequiredArgsConstructor;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;import java.util.List;
@Service@RequiredArgsConstructor@Transactional(readOnly=true)public class ProjectServiceImpl implements ProjectService{private final ProjectRepository projectRepository;private final PortfolioRepository portfolioRepository;public List<ProjectResponse> getProjects(Long portfolioId){return projectRepository.findAllByPortfolioIdOrderByOrderIndex(portfolioId).stream().map(ProjectConverter::toResponse).toList();}@Transactional public ProjectResponse create(Long portfolioId,ProjectCreateRequest r){Portfolio pf=portfolioRepository.findByIdAndDeletedAtIsNull(portfolioId).orElseThrow(()->new CustomException(ErrorCode.PORTFOLIO_NOT_FOUND));Project p=Project.builder().portfolio(pf).name(r.name()).role(r.role()).summary(r.summary()).startDate(r.startDate()).endDate(r.endDate()).skills(r.skills()).build();return ProjectConverter.toResponse(projectRepository.save(p));}@Transactional public ProjectResponse update(Long portfolioId,Long projectId,ProjectUpdateRequest r){Project p=get(portfolioId,projectId);p.update(r.name(),r.role(),r.summary(),r.startDate(),r.endDate(),r.skills());return ProjectConverter.toResponse(p);}@Transactional public void delete(Long portfolioId,Long projectId){projectRepository.delete(get(portfolioId,projectId));}@Transactional public void updateOrders(Long portfolioId,List<ProjectOrderRequest> rs){for(ProjectOrderRequest r:rs)get(portfolioId,r.projectId()).updateOrder(r.orderIndex());}private Project get(Long pid,Long id){return projectRepository.findByIdAndPortfolioId(id,pid).orElseThrow(()->new CustomException(ErrorCode.PROJECT_NOT_FOUND));}}
